@@ -45,7 +45,7 @@
   (
     'non-response-handling',
     'How do I handle non-response in surveys?',
-    '<p><strong>Non-response</strong> occurs when selected sample units do not participate in the survey.</p><h3>How to handle non-response:</h3><ol><li><strong>Follow up</strong> with non-respondents multiple times</li><li><strong>Use different contact methods</strong> (phone, email, in-person)</li><li><strong>Offer incentives</strong> if appropriate and allowed</li><li><strong>Document reasons</strong> for non-response</li><li><strong>Calculate and report</strong> response rates accurately</li></ol><p>High non-response rates can introduce bias into survey results, so it''s important to minimize them through proper survey design and fieldwork procedures.</p>',
+    '<p><strong>Non-response</strong> occurs when selected sample units do not participate in the survey.</p><h3>How to handle non-response:</h3><ol><li><strong>Follow up</strong> with non-respondents multiple times</li><li><strong>Use different contact methods</strong> (phone, email, in-person)</li><li><strong>Offer incentives</strong> if appropriate and allowed</li><li><strong>Document reasons</strong> for non-response</li><li><strong>Calculate and report</strong> response rates accurately</li></ol><p>High non-response rates can introduce bias into survey results, so it''''s important to minimize them through proper survey design and fieldwork procedures.</p>',
     'general',
     '[]'::jsonb,
     'admin'
@@ -54,7 +54,7 @@
   (
     'data-quality-control',
     'What are the key aspects of data quality control?',
-    '<p><strong>Data Quality Control</strong> ensures the accuracy and reliability of collected data.</p><h3>Key aspects include:</h3><ul><li><strong>Real-time validation</strong> during data entry</li><li><strong>Range checks</strong> for numerical values</li><li><strong>Consistency checks</strong> across related fields</li><li><strong>Completeness verification</strong></li><li><strong>Logic checks</strong> for skip patterns</li><li><strong>Supervisor reviews</strong> of completed forms</li></ul><p>Implementing robust quality control measures helps ensure that your survey data is reliable and can support valid conclusions.</p>',
+    '<p><strong>Data Quality Control</strong> ensures the accuracy and reliability of collected data.</p><h3>Key aspects include:</h3><ul><li><strong>Real-time validation</strong> during data entry</li><li><strong>Range checks</strong> for numerical values</li><li><strong>Consistency checks</strong> across related fields</li><li><strong>Completeness verification</strong></li><li><strong>Logic checks</strong> for skip patterns</li><li><strong>Supervisor reviews</strong> of completed forms</li></ul><p>Implementing robust quality control measures helps ensure that your survey data is reliable and can support valid conclusions.</p>',
     'general',
     '[]'::jsonb,
     'admin'
@@ -63,7 +63,7 @@
   (
     'sampling-methods',
     'What are the different sampling methods used in surveys?',
-    '<p><strong>Sampling Methods</strong> determine how you select respondents from the target population.</p><h3>Common methods:</h3><ul><li><strong>Simple Random Sampling</strong> - Every unit has equal chance</li><li><strong>Systematic Sampling</strong> - Select every nth unit</li><li><strong>Stratified Sampling</strong> - Divide population into groups first</li><li><strong>Cluster Sampling</strong> - Select groups, then all units in selected groups</li><li><strong>Multi-stage Sampling</strong> - Combination of methods</li></ul><p>The choice of sampling method depends on your survey objectives, budget, and the nature of your target population.</p>',
+    '<p><strong>Sampling Methods</strong> determine how you select respondents from the target population.</p><h3>Common methods:</h3><ul><li><strong>Simple Random Sampling</strong> - Every unit has equal chance</li><li><strong>Systematic Sampling</strong> - Select every nth unit</li><li><strong>Stratified Sampling</strong> - Divide population into groups first</li><li><strong>Cluster Sampling</strong> - Select groups, then all units in selected groups</li><li><strong>Multi-stage Sampling</strong> - Combination of methods</li></ul><p>The choice of sampling method depends on your survey objectives, budget, and the nature of your target population.</p>',
     'general',
     '[]'::jsonb,
     'admin'
